			Mode:           ModeGeneral,
			IsAllLowercase: true,
		})
	}
	got := fp.BuildMirroring(ModeGeneral)
	if !strings.Contains(got, "Use lowercase") {
		t.Errorf("expected lowercase instruction, got %q", got)
	}
}

