	}
	if !strings.HasSuffix(got, "\n\nMirror their style by default. Use their vocabulary and tone.\n") {
		t.Errorf("wrong footer, got suffix: %q", got[len(got)-80:])
	}
}

func TestBuildMirroringSafeUnderConcurrency(t *testing.T) {
	fp := NewFingerprint()
